export default Header;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Question } from '../types';
import { Shuffle, Filter, ChevronDown, RotateCw, Check, X, ChevronLeft, ChevronRight, Volume2, VolumeX, ImageOff, PenTool } from 'lucide-react';
import Button from './Button';
import { useSpeech } from '../hooks/useSpeech';

interface FlashcardsProps {
  data: Question[];
  onEdit?: (id: string) => void;
}

const Flashcards: React.FC<FlashcardsProps> = ({ data, onEdit }) => {
  const [deck, setDeck] = useState<Question[]>(data);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [isAnimating, setIsAnimating] = useState(false);
  const [direction, setDirection] = useState<'left' | 'right' | 'none'>('none');
  const [imgError, setImgError] = useState(false);
  const [ansImgError, setAnsImgError] = useState(false);

  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);

  const { speak, cancel, isSpeaking, speakingId, hasSupport } = useSpeech();

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category || 'General'));
    return Array.from(cats).sort();
  }, [data]);

  useEffect(() => {
    let filtered = data;
    if (selectedCategories.length > 0) {
      filtered = data.filter(q => selectedCategories.includes(q.category || 'General'));
    }
    setDeck(filtered);
    setCurrentIndex(0);
    setIsFlipped(false);
    setDirection('none');
  }, [data, selectedCategories]);

  useEffect(() => {
    setImgError(false);
    setAnsImgError(false);
    cancel();
  }, [currentIndex, deck, cancel]);

  const toggleCategory = (cat: string) => {
    setSelectedCategories(prev => 
      prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat]
    );
  };

  const flipCard = useCallback(() => {
    if (!isAnimating) {
      setIsAnimating(true);
      setIsFlipped(prev => !prev);
      cancel();
      setTimeout(() => setIsAnimating(false), 400); // Matching duration in CSS
    }
  }, [isAnimating, cancel]);

  const nextCard = useCallback(() => {
    if (currentIndex < deck.length - 1) {
      setIsFlipped(false);
      setDirection('right');
      setTimeout(() => {
        setCurrentIndex(prev => prev + 1);
        setDirection('none');
      }, 150);
    }
  }, [currentIndex, deck.length]);

  const prevCard = useCallback(() => {
    if (currentIndex > 0) {
      setIsFlipped(false);
      setDirection('left');
      setTimeout(() => {
        setCurrentIndex(prev => prev - 1);
        setDirection('none');
      }, 150);
    }
  }, [currentIndex]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return;
      switch (e.key) {
        case 'ArrowRight': nextCard(); break;
        case 'ArrowLeft': prevCard(); break;
        case ' ':
        case 'Enter':
          if (document.activeElement?.tagName !== 'BUTTON') {
            e.preventDefault();
            flipCard();
          }
          break;
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [nextCard, prevCard, flipCard]);

  const handleAudio = (e: React.MouseEvent, text: string, id: string) => {
    e.stopPropagation();
    if (isSpeaking && speakingId === id) {
      cancel();
    } else {
      speak(text, id);
    }
  };

  const currentCard = deck[currentIndex];
  const progressPercent = deck.length > 0 ? ((currentIndex + 1) / deck.length) * 100 : 0;

  return (
    <div className="flex flex-col max-w-5xl mx-auto w-full px-3 md:px-4 h-full focus:outline-none overflow-hidden">

      {/* Progress Bar */}
      <div className="w-full h-1 bg-slate-200 rounded-full mb-4 overflow-hidden shrink-0">
        <div 
          className="h-full bg-blue-600 transition-all duration-500 ease-out"
          style={{ width: `${progressPercent}%` }}
        ></div>
      </div>

      <div className="flex-none mb-2 md:mb-4 flex justify-between items-center gap-2 md:gap-3 z-20">
        <div className="flex items-center gap-2 md:gap-3 flex-1 min-w-0">
            <div className="bg-slate-900 text-white px-3 py-1.5 rounded-lg border border-slate-800 shadow-sm font-black text-[10px] md:text-xs tracking-widest whitespace-nowrap uppercase">
            {deck.length > 0 ? `${currentIndex + 1} / ${deck.length}` : '0'}
            </div>

            <div className="relative flex-1 min-w-0">
                <Button 
                variant="ghost" 
                onClick={() => setIsFilterOpen(!isFilterOpen)}
                className={`flex items-center gap-1 md:gap-2 text-[10px] font-bold uppercase tracking-wider rounded-lg border h-8 px-2 md:px-3 transition-all focus:ring-2 focus:ring-blue-400 w-full md:w-auto justify-between md:justify-start ${selectedCategories.length > 0 ? 'bg-blue-50 text-blue-600 border-blue-200' : 'bg-white border-slate-200 text-slate-500'}`}
                >
                <div className="flex items-center gap-2 truncate">
                    <Filter size={12} className="shrink-0" />
                    <span className="truncate">{selectedCategories.length > 0 ? `${selectedCategories.length} Chapters` : 'Curriculum: All'}</span>
                </div>
                <ChevronDown size={10} className={`transition-transform shrink-0 ${isFilterOpen ? 'rotate-180' : ''}`} />
                </Button>

                {isFilterOpen && (
                <>
                    <div className="fixed inset-0 z-10" onClick={() => setIsFilterOpen(false)}></div>
                    <div className="absolute left-0 top-full mt-2 w-64 md:w-80 bg-white border border-slate-200 rounded-2xl shadow-2xl z-50 flex flex-col max-h-[60vh] focus:outline-none animate-in fade-in slide-in-from-top-2">
                    <div className="p-4 bg-slate-50 border-b border-slate-100 flex justify-between items-center rounded-t-2xl">
                        <span className="text-xs font-black text-slate-400 uppercase tracking-widest">Select Modules</span>
                        <button onClick={() => setSelectedCategories([])} className="text-[10px] font-black text-red-500 hover:text-red-700 uppercase">Clear</button>
                    </div>
                    <div className="overflow-y-auto p-2 custom-scrollbar">
                        {categories.map(cat => (
                        <label key={cat} className="flex items-center gap-3 p-3 hover:bg-slate-50 rounded-xl cursor-pointer transition-colors group">
                            <div className={`w-5 h-5 rounded-md border-2 flex items-center justify-center transition-colors ${selectedCategories.includes(cat) ? 'bg-blue-600 border-blue-600 shadow-md shadow-blue-200' : 'border-slate-200 bg-white'}`}>
                            {selectedCategories.includes(cat) && <Check size={12} className="text-white" strokeWidth={4} />}
                            </div>
                            <span className="text-xs font-bold text-slate-700 leading-tight break-words">{cat}</span>
                            <input type="checkbox" className="hidden" checked={selectedCategories.includes(cat)} onChange={() => toggleCategory(cat)} />
                        </label>
                        ))}
                    </div>
                    </div>
                </>
                )}
            </div>
        </div>

        <Button 
            variant="ghost" 
            onClick={() => {
              const shuffled = [...deck].sort(() => Math.random() - 0.5);
              setDeck(shuffled);
              setCurrentIndex(0);
              setIsFlipped(false);
              setDirection('none');
            }} 
            className="h-8 px-2 md:px-4 text-[10px] font-black text-slate-500 bg-white border border-slate-200 rounded-lg uppercase tracking-widest hover:text-blue-600 hover:border-blue-200 hover:shadow-sm shrink-0 transition-all active:scale-95"
        >
            <Shuffle size={12} className="md:mr-2" /> <span className="hidden md:inline">Shuffle Pack</span>
        </Button>
      </div>

      <div className="flex-1 min-h-0 relative perspective-1000 z-10 group mb-6">
        {deck.length > 0 && currentCard ? (
            <div 
                key={currentCard.id}
                className={`w-full h-full relative transform-style-3d transition-all duration-700 ease-[cubic-bezier(0.34,1.56,0.64,1)] cursor-pointer focus:outline-none focus:ring-4 focus:ring-blue-400/20 rounded-[2.5rem] ${isFlipped ? 'rotate-y-180' : ''} ${direction === 'right' ? 'animate-slide-in-right' : direction === 'left' ? 'animate-slide-in-left' : ''}`}
                onClick={flipCard}
                tabIndex={0}
            >
            <div className="absolute inset-0 w-full h-full bg-white rounded-[2.5rem] shadow-[0_8px_30px_rgb(0,0,0,0.04)] border-2 border-slate-100 backface-hidden flex flex-col overflow-hidden">
              <div className="px-6 py-4 md:px-8 md:pt-6 flex justify-between items-start flex-none">
                <div className="flex flex-col gap-1">
                  <span className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-[0.25em] bg-slate-50 px-3 py-1 rounded-full border border-slate-100">Theory Matrix</span>
                  <span className="text-[8px] font-bold text-blue-500/60 ml-2 uppercase tracking-widest">{currentCard.category}</span>
                </div>
                {hasSupport && (
                  <button onClick={(e) => handleAudio(e, currentCard.questionText, currentCard.id + 'q')} className={`p-2 md:p-3 rounded-2xl transition-all ${isSpeaking && speakingId === currentCard.id + 'q' ? 'bg-red-500 text-white shadow-lg shadow-red-200' : 'bg-slate-50 text-slate-400 hover:bg-blue-600 hover:text-white hover:shadow-lg hover:shadow-blue-200'}`}>
                    {isSpeaking && speakingId === currentCard.id + 'q' ? <VolumeX size={16} /> : <Volume2 size={16} />}
                  </button>
                )}
              </div>

              <div className="flex-1 p-6 md:p-10 flex flex-col items-center justify-center overflow-y-auto custom-scrollbar">
                {currentCard.questionImage && (
                  <div className="mb-6 md:mb-10 flex-none flex flex-col items-center max-w-full">
                    {!imgError ? (
                      <img 
                        src={currentCard.questionImage} 
                        className="max-h-[35vh] md:max-h-[42vh] w-auto object-contain rounded-2xl shadow-xl shadow-slate-100 mix-blend-multiply"
                        onError={() => setImgError(true)}
                        alt="Anatomy Diagram"
                      />
                    ) : (
                      <div className="p-8 bg-red-50 rounded-3xl border-2 border-dashed border-red-200 flex flex-col items-center gap-4 max-w-sm text-center">
                         <ImageOff size={40} className="text-red-300" />
                         <div className="space-y-1">
                            <span className="block text-[11px] font-black text-red-500 uppercase tracking-widest">Image Data Blocked</span>
                            <p className="text-[10px] font-medium text-red-400 leading-tight px-4">Direct image link from source is unreachable. Use the Builder to update this asset.</p>
                         </div>
                         <button 
                          onClick={(e) => { e.stopPropagation(); if(onEdit) onEdit(currentCard.id); }}
                          className="px-6 py-2.5 bg-red-600 text-white rounded-xl text-[10px] font-black uppercase flex items-center gap-2 hover:bg-red-700 transition-all shadow-lg shadow-red-200 active:scale-95"
                         >
                           <PenTool size={12} /> Sync Asset in Builder
                         </button>
                      </div>
                    )}
                  </div>
                )}
                <div className="text-lg md:text-3xl font-black text-center text-slate-900 leading-[1.2] tracking-tight max-w-3xl" dangerouslySetInnerHTML={{ __html: currentCard.questionText }} />
                <div className="mt-8 flex items-center gap-2 opacity-30 text-slate-400 animate-pulse">
                   <div className="w-1.5 h-1.5 bg-current rounded-full"></div>
                   <span className="text-[9px] font-black uppercase tracking-widest">Click to reveal answer</span>
                   <div className="w-1.5 h-1.5 bg-current rounded-full"></div>
                </div>
              </div>
            </div>

            <div className="absolute inset-0 w-full h-full bg-slate-900 rounded-[2.5rem] shadow-[0_25px_60px_rgb(15,23,42,0.4)] border border-slate-800 backface-hidden rotate-y-180 flex flex-col overflow-hidden">
              <div className="px-6 py-4 md:px-8 md:pt-6 flex justify-between items-center flex-none">
                <span className="text-[9px] md:text-[10px] font-black uppercase text-emerald-400 tracking-[0.3em] bg-emerald-400/10 px-3 py-1.5 rounded-full border border-emerald-400/20 shadow-sm shadow-emerald-500/10">Scientific Response</span>
                {hasSupport && (
                  <button onClick={(e) => handleAudio(e, currentCard.answerText + ". " + (currentCard.explanation || ""), currentCard.id + 'a')} className={`p-2 md:p-3 rounded-2xl transition-all ${isSpeaking && speakingId === currentCard.id + 'a' ? 'bg-red-500/40 text-white' : 'bg-white/5 text-white/40 hover:bg-white/20 hover:text-white'}`}>
                    {isSpeaking && speakingId === currentCard.id + 'a' ? <VolumeX size={16} /> : <Volume2 size={16} />}
                  </button>
                )}
              </div>

              <div className="flex-1 p-6 md:p-12 flex flex-col items-center justify-center overflow-y-auto custom-scrollbar">
                {currentCard.answerImage && (
                  <div className="mb-6 md:mb-10 flex-none flex flex-col items-center">
                    {!ansImgError ? (
                      <img 
                        src={currentCard.answerImage} 
                        className="max-h-[35vh] md:max-h-[42vh] w-auto object-contain rounded-2xl shadow-2xl"
                        onError={() => setAnsImgError(true)}
                        alt="Scientific Diagram"
                      />
                    ) : (
                      <div className="p-6 bg-white/5 rounded-[2rem] border-2 border-dashed border-white/10 flex flex-col items-center gap-3">
                        <ImageOff size={32} className="text-white/20" />
                        <button onClick={(e) => { e.stopPropagation(); if(onEdit) onEdit(currentCard.id); }} className="text-[10px] font-black text-blue-400 uppercase tracking-widest hover:underline hover:text-blue-300">Sync Answer Asset</button>
                      </div>
                    )}
                  </div>
                )}
                <div className="text-xl md:text-4xl font-black text-center text-white leading-[1.1] tracking-tight mb-8" dangerouslySetInnerHTML={{ __html: currentCard.answerText }} />
                {currentCard.explanation && (
                  <div className="bg-white/[0.03] p-5 md:p-8 rounded-[2rem] border border-white/10 text-slate-300 text-sm md:text-lg leading-relaxed max-w-2xl text-center backdrop-blur-xl shadow-inner group-hover:bg-white/[0.05] transition-colors">
                    <span className="text-blue-500 font-black uppercase text-[10px] md:text-xs tracking-[0.3em] block mb-4">Anatomical Correlation</span>
                    <span className="font-medium opacity-90" dangerouslySetInnerHTML={{ __html: currentCard.explanation }} />
                  </div>
                )}
              </div>
            </div>
          </div>
        ) : (
            <div className="w-full h-full flex flex-col items-center justify-center bg-white rounded-[3rem] border-2 border-dashed border-slate-200 text-slate-400 p-12 text-center shadow-inner">
                <div className="p-8 bg-slate-50 rounded-full mb-6">
                  <Filter size={64} className="opacity-20" />
                </div>
                <p className="font-black text-2xl text-slate-600 tracking-tight">No active nodes in this sequence.</p>
                <p className="text-slate-400 font-bold mt-2 uppercase tracking-widest text-xs">Try adjusting your filters or search criteria.</p>
                <button 
                  onClick={() => setSelectedCategories([])} 
                  className="mt-8 px-8 py-4 bg-slate-900 text-white font-black rounded-2xl uppercase tracking-widest text-xs hover:bg-blue-600 transition-all shadow-xl shadow-slate-200 active:scale-95"
                >
                  Reset Sequence
                </button>
            </div>
        )}
      </div>

      <div className="flex-none flex items-center justify-center gap-4 md:gap-6 w-full mb-6">
        <button 
          onClick={prevCard} 
          disabled={currentIndex === 0} 
          className="h-14 w-16 md:h-16 md:w-24 rounded-[1.5rem] bg-white border-2 border-slate-100 text-slate-400 hover:text-blue-600 hover:border-blue-200 hover:bg-blue-50 transition-all disabled:opacity-20 disabled:cursor-not-allowed flex items-center justify-center shrink-0 outline-none active:scale-90 shadow-sm"
        >
          <ChevronLeft size={28} className="md:w-8 md:h-8" />
        </button>

        <button 
          onClick={flipCard} 
          className="h-14 md:h-16 flex-1 max-w-sm rounded-[1.5rem] bg-slate-900 text-white font-black uppercase tracking-[0.2em] shadow-2xl shadow-slate-900/20 hover:bg-blue-600 hover:-translate-y-1 active:scale-95 transition-all flex items-center justify-center gap-4 text-xs md:text-sm"
        >
          <RotateCw size={18} className={`md:w-5 md:h-5 transition-transform duration-700 ${isFlipped ? "-rotate-180" : ""}`} />
          {isFlipped ? 'See Question' : 'Reveal Data'}
        </button>

        <button 
          onClick={nextCard} 
          disabled={currentIndex === deck.length - 1} 
          className="h-14 w-16 md:h-16 md:w-24 rounded-[1.5rem] bg-white border-2 border-slate-100 text-slate-400 hover:text-blue-600 hover:border-blue-200 hover:bg-blue-50 transition-all disabled:opacity-20 disabled:cursor-not-allowed flex items-center justify-center shrink-0 outline-none active:scale-90 shadow-sm"
        >
          <ChevronRight size={28} className="md:w-8 md:h-8" />
        </button>
      </div>
    </div>
  );
};

export default Flashcards;

