                                      <div className={`mt-0.5 w-6 h-6 rounded-md border flex items-center justify-center text-[10px] font-black ${showResult && isCorrect ? 'bg-emerald-500 text-white border-emerald-500' : 'text-slate-400'}`}>{String.fromCharCode(65 + idx)}</div>
