import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Question } from '../types';
import { Shuffle, Filter, ChevronDown, RotateCw, Check, ChevronLeft, ChevronRight, Volume2, VolumeX, ImageOff, ExternalLink } from 'lucide-react';
import Button from './Button';
import { useSpeech } from '../hooks/useSpeech';

interface FlashcardsProps {
  data: Question[];
  onEdit?: (id: string) => void;
}

const Flashcards: React.FC<FlashcardsProps> = ({ data, onEdit }) => {
  const [deck, setDeck] = useState<Question[]>(data);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [isAnimating, setIsAnimating] = useState(false);
  const [direction, setDirection] = useState<'left' | 'right' | 'none'>('none');
  const [imgLoadError, setImgLoadError] = useState<Record<string, boolean>>({});

  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);

  const { speak, cancel, isSpeaking, speakingId, hasSupport } = useSpeech();

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category || 'General'));
    return Array.from(cats).sort();
  }, [data]);

  useEffect(() => {
    let filtered = data;
    if (selectedCategories.length > 0) {
      filtered = data.filter(q => selectedCategories.includes(q.category || 'General'));
    }
    setDeck(filtered);
    setCurrentIndex(0);
    setIsFlipped(false);
    setDirection('none');
  }, [data, selectedCategories]);

  useEffect(() => {
    cancel();
  }, [currentIndex, deck, cancel]);

  const toggleCategory = (cat: string) => {
    setSelectedCategories(prev => 
      prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat]
    );
  };

  const flipCard = useCallback(() => {
    if (!isAnimating) {
      setIsAnimating(true);
      setIsFlipped(prev => !prev);
      cancel();
      setTimeout(() => setIsAnimating(false), 400);
    }
  }, [isAnimating, cancel]);

  const nextCard = useCallback(() => {
    if (currentIndex < deck.length - 1) {
      setIsFlipped(false);
      setDirection('right');
      setTimeout(() => {
        setCurrentIndex(prev => prev + 1);
        setDirection('none');
      }, 150);
    }
  }, [currentIndex, deck.length]);

  const prevCard = useCallback(() => {
    if (currentIndex > 0) {
      setIsFlipped(false);
      setDirection('left');
      setTimeout(() => {
        setCurrentIndex(prev => prev - 1);
        setDirection('none');
      }, 150);
    }
  }, [currentIndex]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return;
      switch (e.key) {
        case 'ArrowRight': nextCard(); break;
        case 'ArrowLeft': prevCard(); break;
        case ' ':
        case 'Enter':
          if (document.activeElement?.tagName !== 'BUTTON') {
            e.preventDefault();
            flipCard();
          }
          break;
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [nextCard, prevCard, flipCard]);

  const handleAudio = (e: React.MouseEvent, text: string, id: string) => {
    e.stopPropagation();
    if (isSpeaking && speakingId === id) {
      cancel();
    } else {
      speak(text, id);
    }
  };

  const handleImageError = (id: string) => {
    setImgLoadError(prev => ({ ...prev, [id]: true }));
  };

  const currentCard = deck[currentIndex];
  const progressPercent = deck.length > 0 ? ((currentIndex + 1) / deck.length) * 100 : 0;

  return (
    <div className="flex flex-col max-w-5xl mx-auto w-full px-3 md:px-4 h-full focus:outline-none overflow-hidden">

      <div className="w-full h-1 bg-slate-200 rounded-full mb-4 overflow-hidden shrink-0">
        <div 
          className="h-full bg-red-600 transition-all duration-500 ease-out"
          style={{ width: `${progressPercent}%` }}
        ></div>
      </div>

      <div className="flex-none mb-2 md:mb-4 flex justify-between items-center gap-2 md:gap-3 z-20">
        <div className="flex items-center gap-2 md:gap-3 flex-1 min-w-0">
            <div className="bg-slate-900 text-white px-3 py-1.5 rounded-lg font-black text-[10px] md:text-xs tracking-widest whitespace-nowrap uppercase">
            {deck.length > 0 ? `${currentIndex + 1} / ${deck.length}` : '0'}
            </div>

            <div className="relative flex-1 min-w-0">
                <Button 
                variant="ghost" 
                onClick={() => setIsFilterOpen(!isFilterOpen)}
                className={`flex items-center gap-1 md:gap-2 text-[10px] font-bold uppercase tracking-wider rounded-lg border h-8 px-2 md:px-3 transition-all ${selectedCategories.length > 0 ? 'bg-red-50 text-red-600 border-red-200' : 'bg-white border-slate-200 text-slate-500'}`}
                >
                <Filter size={12} className="shrink-0" />
                <span className="truncate">{selectedCategories.length > 0 ? `${selectedCategories.length} Chapters` : 'All Topics'}</span>
                <ChevronDown size={10} className={`transition-transform shrink-0 ${isFilterOpen ? 'rotate-180' : ''}`} />
                </Button>

                {isFilterOpen && (
                <>
                    <div className="fixed inset-0 z-10" onClick={() => setIsFilterOpen(false)}></div>
                    <div className="absolute left-0 top-full mt-2 w-64 md:w-80 bg-white border border-slate-200 rounded-2xl shadow-2xl z-50 flex flex-col max-h-[60vh] animate-in fade-in slide-in-from-top-2">
                    <div className="p-4 bg-slate-50 border-b border-slate-100 flex justify-between items-center rounded-t-2xl">
                        <span className="text-xs font-black text-slate-400 uppercase tracking-widest">Filters</span>
                        <button onClick={() => setSelectedCategories([])} className="text-[10px] font-black text-red-500 uppercase">Clear</button>
                    </div>
                    <div className="overflow-y-auto p-2 custom-scrollbar">
                        {categories.map(cat => (
                        <label key={cat} className="flex items-center gap-3 p-3 hover:bg-slate-50 rounded-xl cursor-pointer transition-colors group">
                            <div className={`w-5 h-5 rounded-md border-2 flex items-center justify-center transition-colors ${selectedCategories.includes(cat) ? 'bg-red-600 border-red-600 shadow-md shadow-red-100' : 'border-slate-200 bg-white'}`}>
                            {selectedCategories.includes(cat) && <Check size={12} className="text-white" strokeWidth={4} />}
                            </div>
                            <span className="text-xs font-bold text-slate-700 leading-tight">{cat}</span>
                            <input type="checkbox" className="hidden" checked={selectedCategories.includes(cat)} onChange={() => toggleCategory(cat)} />
                        </label>
                        ))}
                    </div>
                    </div>
                </>
                )}
            </div>
        </div>

        <Button 
            variant="ghost" 
            onClick={() => {
              const shuffled = [...deck].sort(() => Math.random() - 0.5);
              setDeck(shuffled);
              setCurrentIndex(0);
              setIsFlipped(false);
              setDirection('none');
            }} 
            className="h-8 px-2 md:px-4 text-[10px] font-black text-slate-500 bg-white border border-slate-200 rounded-lg uppercase tracking-widest hover:text-red-600 transition-all"
        >
            <Shuffle size={12} className="md:mr-2" /> <span className="hidden md:inline">Shuffle</span>
        </Button>
      </div>

      <div className="flex-1 min-h-0 relative perspective-1000 z-10 mb-6">
        {deck.length > 0 && currentCard ? (
            <div 
                key={currentCard.id}
                className={`w-full h-full relative transform-style-3d transition-all duration-700 ease-[cubic-bezier(0.34,1.56,0.64,1)] cursor-pointer rounded-[2.5rem] ${isFlipped ? 'rotate-y-180' : ''} ${direction === 'right' ? 'animate-slide-in-right' : direction === 'left' ? 'animate-slide-in-left' : ''}`}
                onClick={flipCard}
                tabIndex={0}
            >
            {/* FRONT OF CARD */}
            <div className="absolute inset-0 w-full h-full bg-white rounded-[2.5rem] shadow-xl border border-slate-100 backface-hidden flex flex-col overflow-hidden">
              <div className="px-6 py-4 md:px-8 md:pt-6 flex justify-between items-start">
                <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest">{currentCard.category}</span>
                {hasSupport && (
                  <button onClick={(e) => handleAudio(e, currentCard.questionText, currentCard.id + 'q')} className={`p-2 rounded-xl transition-all ${isSpeaking && speakingId === currentCard.id + 'q' ? 'bg-red-500 text-white shadow-lg' : 'bg-slate-50 text-slate-400 hover:bg-red-50 hover:text-red-600'}`}>
                    {isSpeaking && speakingId === currentCard.id + 'q' ? <VolumeX size={16} /> : <Volume2 size={16} />}
                  </button>
                )}
              </div>

              <div className="flex-1 p-6 md:p-10 flex flex-col items-center justify-center overflow-y-auto custom-scrollbar text-center">
                {currentCard.questionImage && (
                  <div className="mb-6 md:mb-10 flex-none w-full max-w-lg relative group/img">
                      {!imgLoadError[currentCard.id + '_q'] ? (
                        <img 
                          src={currentCard.questionImage} 
                          referrerPolicy="no-referrer"
                          className="max-h-[35vh] md:max-h-[42vh] w-auto mx-auto object-contain rounded-xl"
                          alt="Anatomy Question"
                          onError={() => handleImageError(currentCard.id + '_q')}
                        />
                      ) : (
                        <div className="flex flex-col items-center p-6 bg-slate-50 rounded-2xl border-2 border-dashed border-slate-200">
                          <ImageOff size={40} className="text-slate-300 mb-2" />
                          <p className="text-[10px] font-bold text-slate-400 uppercase mb-3">Host Blocked Image</p>
                          <a 
                            href={currentCard.questionImage} 
                            target="_blank" 
                            rel="noopener noreferrer" 
                            onClick={(e) => e.stopPropagation()}
                            className="flex items-center gap-2 px-4 py-2 bg-slate-900 text-white rounded-lg text-[10px] font-black uppercase hover:bg-blue-600 transition-colors"
                          >
                            Open Original <ExternalLink size={12} />
                          </a>
                        </div>
                      )}
                  </div>
                )}
                <div className="text-xl md:text-3xl font-black text-slate-900 leading-tight" dangerouslySetInnerHTML={{ __html: currentCard.questionText }} />
              </div>
            </div>

            {/* BACK OF CARD */}
            <div className="absolute inset-0 w-full h-full bg-slate-900 rounded-[2.5rem] shadow-2xl border border-slate-800 backface-hidden rotate-y-180 flex flex-col overflow-hidden">
              <div className="px-6 py-4 md:px-8 md:pt-6 flex justify-between items-center">
                <span className="text-[10px] font-black uppercase text-red-500 tracking-widest">Solution</span>
                {hasSupport && (
                  <button onClick={(e) => handleAudio(e, currentCard.answerText + ". " + (currentCard.explanation || ""), currentCard.id + 'a')} className={`p-2 rounded-xl transition-all ${isSpeaking && speakingId === currentCard.id + 'a' ? 'bg-red-500 text-white' : 'bg-white/5 text-white/40 hover:bg-white/20 hover:text-white'}`}>
                    {isSpeaking && speakingId === currentCard.id + 'a' ? <VolumeX size={16} /> : <Volume2 size={16} />}
                  </button>
                )}
              </div>

              <div className="flex-1 p-6 md:p-12 flex flex-col items-center justify-center overflow-y-auto custom-scrollbar text-center">
                {currentCard.answerImage && (
                  <div className="mb-6 md:mb-10 flex-none w-full max-w-lg relative group/img">
                      {!imgLoadError[currentCard.id + '_a'] ? (
                        <img 
                          src={currentCard.answerImage} 
                          referrerPolicy="no-referrer"
                          className="max-h-[35vh] md:max-h-[42vh] w-auto mx-auto object-contain rounded-xl"
                          alt="Anatomy Answer"
                          onError={() => handleImageError(currentCard.id + '_a')}
                        />
                      ) : (
                        <div className="flex flex-col items-center p-6 bg-white/5 rounded-2xl border-2 border-dashed border-white/10">
                          <ImageOff size={40} className="text-white/20 mb-2" />
                          <p className="text-[10px] font-bold text-white/40 uppercase mb-3">Host Blocked Image</p>
                          <a 
                            href={currentCard.answerImage} 
                            target="_blank" 
                            rel="noopener noreferrer" 
                            onClick={(e) => e.stopPropagation()}
                            className="flex items-center gap-2 px-4 py-2 bg-white/10 text-white rounded-lg text-[10px] font-black uppercase hover:bg-white/20 transition-colors"
                          >
                            Open Original <ExternalLink size={12} />
                          </a>
                        </div>
                      )}
                  </div>
                )}
                <div className="text-2xl md:text-4xl font-black text-white leading-tight mb-8" dangerouslySetInnerHTML={{ __html: currentCard.answerText }} />
                {currentCard.explanation && (
                  <div className="bg-white/5 p-6 rounded-2xl border border-white/10 text-slate-300 text-sm md:text-lg leading-relaxed max-w-2xl">
                    <span dangerouslySetInnerHTML={{ __html: currentCard.explanation }} />
                  </div>
                )}
              </div>
            </div>
          </div>
        ) : (
            <div className="w-full h-full flex flex-col items-center justify-center bg-white rounded-[2.5rem] border-2 border-dashed border-slate-200 text-slate-400 p-12 text-center">
                <p className="font-black text-2xl text-slate-600">No content available.</p>
                <button onClick={() => setSelectedCategories([])} className="mt-6 px-8 py-3 bg-slate-900 text-white font-black rounded-xl uppercase text-xs">Reset All</button>
            </div>
        )}
      </div>

      <div className="flex-none flex items-center justify-center gap-4 md:gap-6 w-full mb-6">
        <button 
          onClick={prevCard} 
          disabled={currentIndex === 0} 
          className="h-14 w-16 md:h-16 md:w-24 rounded-[1.5rem] bg-white border-2 border-slate-100 text-slate-400 hover:text-red-600 transition-all disabled:opacity-20 flex items-center justify-center active:scale-90"
        >
          <ChevronLeft size={28} className="md:w-8 md:h-8" />
        </button>

        <button 
          onClick={flipCard} 
          className="h-14 md:h-16 flex-1 max-w-sm rounded-[1.5rem] bg-slate-900 text-white font-black uppercase tracking-widest shadow-xl hover:bg-red-600 transition-all flex items-center justify-center gap-4 text-xs md:text-sm"
        >
          <RotateCw size={18} className={`transition-transform duration-700 ${isFlipped ? "-rotate-180" : ""}`} />
          {isFlipped ? 'Show Question' : 'Show Answer'}
        </button>

        <button 
          onClick={nextCard} 
          disabled={currentIndex === deck.length - 1} 
          className="h-14 w-16 md:h-16 md:w-24 rounded-[1.5rem] bg-white border-2 border-slate-100 text-slate-400 hover:text-red-600 transition-all disabled:opacity-20 flex items-center justify-center active:scale-90"
        >
          <ChevronRight size={28} className="md:w-8 md:h-8" />
        </button>
      </div>
    </div>
  );
};

export default Flashcards;

import React, { useState, useEffect, useMemo } from 'react';
import { Question, QuizQuestion } from '../types';
import Button from './Button';
import { 
  RotateCcw, BrainCircuit, Check, X, Clock, Flag, ChevronLeft, ChevronRight, 
  LayoutGrid, Image as ImageIcon, Zap, Hash, Filter, CheckCircle2, 
  Lightbulb, Shuffle, Play, Trophy, Target, List, AlertTriangle, 
  Medal, Dna, Layers, RotateCw, ThumbsUp, ThumbsDown, ImageOff, ExternalLink
} from 'lucide-react';

const SESSION_KEY = 'anatomy_quiz_session_v1';
const SETTINGS_KEY = 'anatomy_quiz_settings_v1';
const MISTAKES_KEY = 'anatomy_quiz_mistakes_v1';

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
  onEdit?: (id: string) => void;
}

const Quiz: React.FC<QuizProps> = ({ data, onEdit }) => {
  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>('setup');
  const [mode, setMode] = useState<'exam' | 'practice' | 'mistakes' | 'flashcard'>('exam');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [imgLoadError, setImgLoadError] = useState<Record<string, boolean>>({});

  const [questionCount, setQuestionCount] = useState(25);
  const [selectedGroups, setSelectedGroups] = useState<string[]>([]);
  const [showImagesOnly, setShowImagesOnly] = useState(false);
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
  const [showExplanations, setShowExplanations] = useState(true);
  const [shuffleQuestions, setShuffleQuestions] = useState(true);
  const [mistakesHistory, setMistakesHistory] = useState<string[]>([]);

  useEffect(() => {
    const savedSettings = localStorage.getItem(SETTINGS_KEY);
    if (savedSettings) {
      try {
        const parsed = JSON.parse(savedSettings);
        if (parsed.customQuestionCount) setQuestionCount(parsed.customQuestionCount);
        if (parsed.showImagesOnly !== undefined) setShowImagesOnly(parsed.showImagesOnly);
        if (parsed.selectedGroups) setSelectedGroups(parsed.selectedGroups);
        if (parsed.mode && parsed.mode !== 'mistakes') setMode(parsed.mode);
        if (parsed.showExplanations !== undefined) setShowExplanations(parsed.showExplanations);
        if (parsed.shuffleQuestions !== undefined) setShuffleQuestions(parsed.shuffleQuestions);
      } catch (e) {}
    }
    const savedSession = localStorage.getItem(SESSION_KEY);
    if (savedSession) {
      try {
        const parsed = JSON.parse(savedSession);
        if ((parsed.status === 'playing' || parsed.status === 'review') && parsed.questions?.length > 0) {
          setQuestions(parsed.questions);
          setCurrentQIndex(parsed.currentQIndex || 0);
          setTimeLeft(parsed.timeLeft || 0);
          setMode(parsed.mode || 'exam');
          setView(parsed.status);
        }
      } catch (e) {}
    }
    const savedMistakes = localStorage.getItem(MISTAKES_KEY);
    if (savedMistakes) {
      try { setMistakesHistory(JSON.parse(savedMistakes)); } catch (e) {}
    }
  }, []);

  useEffect(() => {
    const settings = {
      customQuestionCount: questionCount,
      showImagesOnly,
      selectedGroups,
      mode: mode === 'mistakes' ? 'exam' : mode,
      showExplanations,
      shuffleQuestions
    };
    localStorage.setItem(SETTINGS_KEY, JSON.stringify(settings));
  }, [questionCount, showImagesOnly, selectedGroups, mode, showExplanations, shuffleQuestions]);

  useEffect(() => {
    if (view === 'playing' || view === 'review') {
      localStorage.setItem(SESSION_KEY, JSON.stringify({ questions, currentQIndex, timeLeft, status: view, mode }));
    } else {
      localStorage.removeItem(SESSION_KEY);
    }
  }, [questions, currentQIndex, timeLeft, view, mode]);

  useEffect(() => {
    if (view === 'results') {
      const newMistakes = new Set(mistakesHistory);
      questions.forEach(q => {
        if (q.userAnswer === q.correctOption) newMistakes.delete(q.id);
        else if (q.userAnswer) newMistakes.add(q.id);
      });
      const updatedMistakes = Array.from(newMistakes);
      localStorage.setItem(MISTAKES_KEY, JSON.stringify(updatedMistakes));
      setMistakesHistory(updatedMistakes);
    }
  }, [view]);

  useEffect(() => {
    setIsFlipped(false);
  }, [currentQIndex]);

  const availableGroups = useMemo(() => {
    const groups = new Set<string>();
    data.forEach(q => { if (q.category) groups.add(q.category); });
    return Array.from(groups).sort();
  }, [data]);

  const maxPossibleQuestions = useMemo(() => {
    return data.filter(q => {
      if (showImagesOnly && !q.questionImage) return false;
      if (!q.answerText) return false;
      const cat = q.category || 'General';
      if (selectedGroups.length > 0 && !selectedGroups.includes(cat)) return false;
      return true;
    }).length;
  }, [data, selectedGroups, showImagesOnly]);

  const generateQuiz = (pool: Question[], count: number) => {
    let selected = [...pool];
    if (shuffleQuestions) selected.sort(() => Math.random() - 0.5);
    else selected.sort((a, b) => a.id.localeCompare(b.id));
    selected = selected.slice(0, count);

    return selected.map(q => {
      const correct = q.answerText;
      let options: string[] = q.options?.length ? Array.from(new Set([...q.options, correct])) : [correct];
      if (options.length < 4) {
        const distractors = data
          .filter(d => d.category === q.category && d.answerText !== correct)
          .map(d => d.answerText);
        options = Array.from(new Set([...options, ...distractors])).slice(0, 4);
      }
      while (options.length < 4) options.push(`Alt ${options.length}`);
      return {
        id: q.id, data: q, options: options.sort(() => Math.random() - 0.5),
        correctOption: correct, userAnswer: null, isFlagged: false
      } as QuizQuestion;
    });
  };

  const startQuiz = () => {
    let pool = data.filter(q => q.answerText && (!showImagesOnly || q.questionImage));
    if (selectedGroups.length > 0) pool = pool.filter(q => selectedGroups.includes(q.category || 'General'));
    if (pool.length === 0) return alert("No questions found.");
    const count = Math.min(questionCount, pool.length);
    setQuestions(generateQuiz(pool, count));
    setCurrentQIndex(0);
    setTimeLeft(count * 60);
    setView('playing');
  };

  const startMistakesReview = () => {
    const pool = data.filter(q => mistakesHistory.includes(q.id));
    if (pool.length === 0) return alert("No mistakes found!");
    setMode('mistakes');
    setQuestions(generateQuiz(pool, pool.length));
    setCurrentQIndex(0);
    setTimeLeft(pool.length * 60);
    setView('playing');
  };

  useEffect(() => {
    if (view !== 'playing' || mode === 'practice' || mode === 'flashcard') return;
    const timer = setInterval(() => setTimeLeft(prev => Math.max(0, prev - 1)), 1000);
    return () => clearInterval(timer);
  }, [view, mode]);

  useEffect(() => {
    if (timeLeft === 0 && view === 'playing' && mode !== 'practice' && mode !== 'flashcard') setView('results');
  }, [timeLeft, view, mode]);

  const handleAnswer = (option: string) => {
    if (view === 'review') return;
    if ((mode === 'practice' || mode === 'flashcard') && questions[currentQIndex].userAnswer) return;
    setQuestions(prev => {
      const copy = [...prev];
      copy[currentQIndex].userAnswer = option;
      return copy;
    });
    if (mode === 'flashcard' && currentQIndex < questions.length - 1) setTimeout(() => setCurrentQIndex(prev => prev + 1), 300);
  };

  const toggleFlag = (index: number = currentQIndex) => {
    setQuestions(prev => {
      const copy = [...prev];
      copy[index].isFlagged = !copy[index].isFlagged;
      return copy;
    });
  };

  const handleFinishSession = () => {
    if (view === 'review') { setView('setup'); return; }
    if (confirm("Submit session?")) { setView('results'); }
  };

  const handleImageError = (id: string) => {
    setImgLoadError(prev => ({ ...prev, [id]: true }));
  };

  if (view === 'setup') {
    return (
      <div className="flex flex-col h-full bg-slate-50 overflow-y-auto p-4 md:p-8">
        <div className="w-full max-w-5xl mx-auto bg-white rounded-3xl shadow-xl border border-slate-200 overflow-hidden">
          <div className="bg-slate-900 p-6 flex items-center justify-between">
            <h1 className="text-2xl font-black text-white flex items-center gap-3"><LayoutGrid className="text-red-600" /> Assessment Setup</h1>
            <div className="text-right"><div className="text-xl font-black text-white">{maxPossibleQuestions}</div><div className="text-[10px] text-slate-500 uppercase font-bold">Bank</div></div>
          </div>
          <div className="p-6 space-y-6">
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
              {[ {id: 'exam', icon: Clock, label: 'Exam', sub: 'Timed', color: 'red'}, {id: 'practice', icon: Zap, label: 'Practice', sub: 'Instant', color: 'blue'}, {id: 'flashcard', icon: Layers, label: 'Cards', sub: 'Manual', color: 'amber'} ].map(m => (
                <button key={m.id} onClick={() => setMode(m.id as any)} className={`p-4 rounded-2xl border-2 transition-all flex flex-col items-center gap-2 ${mode === m.id ? `border-${m.color}-500 bg-${m.color}-50` : 'border-slate-100 hover:bg-slate-50'}`}>
                  <m.icon className={`text-${m.color}-500`} />
                  <div className="font-black text-sm">{m.label}</div>
                  <div className="text-[9px] font-bold opacity-50 uppercase">{m.sub}</div>
                </button>
              ))}
            </div>

            {mistakesHistory.length > 0 && (
              <div className="bg-amber-50 p-4 rounded-2xl flex items-center justify-between border-l-4 border-amber-400">
                <div className="flex items-center gap-3 text-amber-900 font-bold text-sm"><BrainCircuit /> {mistakesHistory.length} Mistakes to Review</div>
                <button onClick={startMistakesReview} className="px-4 py-2 bg-amber-500 text-white rounded-lg text-xs font-black uppercase">Review</button>
              </div>
            )}

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-3">
                <label className="text-xs font-black text-slate-400 uppercase tracking-widest">Question Bank</label>
                <button onClick={() => setIsDropdownOpen(!isDropdownOpen)} className="w-full flex items-center justify-between p-4 bg-white border-2 border-slate-100 rounded-xl font-bold text-sm">
                  <span className="flex items-center gap-2"><Filter size={16} className="text-red-500" /> {selectedGroups.length || 'All'} Topics</span>
                  <ChevronRight className={isDropdownOpen ? 'rotate-90' : ''} />
                </button>
                {isDropdownOpen && (
                  <div className="bg-white border border-slate-100 rounded-xl p-2 max-h-48 overflow-y-auto custom-scrollbar shadow-inner grid gap-1">
                    {availableGroups.map(g => (
                      <label key={g} className="flex items-center gap-2 p-2 hover:bg-slate-50 rounded-lg cursor-pointer text-xs font-bold">
                        <input type="checkbox" checked={selectedGroups.includes(g)} onChange={() => {
                          setSelectedGroups(prev => prev.includes(g) ? prev.filter(x => x !== g) : [...prev, g]);
                        }} /> {g}
                      </label>
                    ))}
                  </div>
                )}
              </div>
              <div className="space-y-3">
                <label className="text-xs font-black text-slate-400 uppercase tracking-widest">Quantity: {questionCount}</label>
                <input type="range" min="1" max={maxPossibleQuestions} value={questionCount} onChange={e => setQuestionCount(parseInt(e.target.value))} className="w-full accent-red-600 h-2 bg-slate-100 rounded-lg appearance-none cursor-pointer" />
                <div className="flex gap-4">
                  <button onClick={() => setShowImagesOnly(!showImagesOnly)} className={`flex-1 p-2 rounded-lg border text-[10px] font-black uppercase flex items-center justify-center gap-2 ${showImagesOnly ? 'bg-red-600 text-white border-red-600' : 'bg-slate-50 text-slate-400'}`}><ImageIcon size={14}/> Diagrams</button>
                  <button onClick={() => setShuffleQuestions(!shuffleQuestions)} className={`flex-1 p-2 rounded-lg border text-[10px] font-black uppercase flex items-center justify-center gap-2 ${shuffleQuestions ? 'bg-slate-900 text-white' : 'bg-slate-50 text-slate-400'}`}><Shuffle size={14}/> Shuffle</button>
                </div>
              </div>
            </div>
            <Button onClick={startQuiz} fullWidth className="py-5 text-xl rounded-2xl bg-red-600 shadow-xl shadow-red-100">Start Session</Button>
          </div>
        </div>
      </div>
    );
  }

  const currentQ = questions[currentQIndex];

  return (
    <div className="h-full flex flex-col w-full bg-slate-50 relative overflow-hidden">
      <div className="max-w-6xl mx-auto w-full h-full p-2 md:p-4 flex gap-4 overflow-hidden">
         <div className="flex-1 flex flex-col h-full gap-2 min-w-0">
            <div className="flex justify-between items-center bg-white p-2 rounded-2xl border border-slate-200 shadow-sm shrink-0">
               <div className="flex items-center gap-3">
                  <span className="px-2.5 py-1 bg-slate-900 text-white rounded-lg text-[10px] font-black uppercase">Q {currentQIndex + 1}</span>
                  <span className="text-[10px] font-bold text-slate-500 uppercase hidden sm:block truncate max-w-[200px]">{currentQ.data.category}</span>
               </div>
               <div className="flex items-center gap-2">
                  <div className="bg-slate-50 px-3 py-1.5 rounded-lg border border-slate-200 font-mono font-black text-xs">{(mode === 'practice' || mode === 'flashcard') ? '--:--' : formatTime(timeLeft)}</div>
                  <button onClick={() => toggleFlag()} className={`p-2 rounded-lg border transition-all ${currentQ.isFlagged ? 'bg-amber-100 border-amber-200 text-amber-700' : 'bg-white border-slate-200 text-slate-400'}`}><Flag size={14} className={currentQ.isFlagged ? "fill-current" : ""} /></button>
                  <button onClick={() => confirm('End session?') && setView('setup')} className="p-2 rounded-lg bg-white border border-slate-200 text-slate-400 hover:text-red-500"><X size={18} /></button>
               </div>
            </div>

            <div className="flex-1 bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden flex flex-col">
               <div className="flex-1 overflow-y-auto p-4 md:p-10 custom-scrollbar">
                  <div className="max-w-3xl mx-auto space-y-6">
                     {mode === 'flashcard' && view === 'playing' ? (
                       <div className="h-full flex flex-col">
                          <div onClick={() => setIsFlipped(!isFlipped)} className={`flex-1 relative cursor-pointer perspective-1000 transition-all duration-500 ${isFlipped ? '[transform:rotateY(180deg)]' : ''}`} style={{ transformStyle: 'preserve-3d' }}>
                              <div className="absolute inset-0 bg-white border-2 border-slate-100 rounded-[2rem] flex flex-col items-center justify-center p-6 backface-hidden shadow-sm">
                                  {currentQ.data.questionImage && (
                                      <div className="mb-6 max-h-[40vh] w-full flex flex-col items-center justify-center">
                                        {!imgLoadError[currentQ.id + '_q'] ? (
                                          <img 
                                            src={currentQ.data.questionImage} 
                                            referrerPolicy="no-referrer"
                                            className="max-h-full object-contain rounded-xl" 
                                            alt="Diagram" 
                                            onError={() => handleImageError(currentQ.id + '_q')}
                                          />
                                        ) : (
                                          <div className="p-4 bg-slate-50 border-2 border-dashed border-slate-200 rounded-xl text-center">
                                            <ImageOff size={32} className="text-slate-300 mx-auto mb-2" />
                                            <a href={currentQ.data.questionImage} target="_blank" rel="noopener noreferrer" onClick={(e) => e.stopPropagation()} className="text-[10px] font-black text-blue-600 uppercase flex items-center gap-1">Open <ExternalLink size={10}/></a>
                                          </div>
                                        )}
                                      </div>
                                  )}
                                  <div className="text-xl md:text-3xl font-black text-center text-slate-900 leading-tight" dangerouslySetInnerHTML={{ __html: currentQ.data.questionText }} />
                              </div>
                              <div className="absolute inset-0 bg-slate-900 border-2 border-slate-800 rounded-[2rem] flex flex-col items-center justify-center p-6 backface-hidden shadow-2xl [transform:rotateY(180deg)] overflow-hidden">
                                  <div className="text-2xl md:text-4xl font-black text-center text-white leading-tight" dangerouslySetInnerHTML={{ __html: currentQ.data.answerText }} />
                                  {currentQ.data.explanation && <div className="mt-8 bg-white/5 border border-white/10 p-6 rounded-2xl text-slate-300 text-sm max-w-md text-center" dangerouslySetInnerHTML={{ __html: currentQ.data.explanation }} />}
                              </div>
                          </div>
                          {isFlipped && !currentQ.userAnswer && (
                              <div className="flex gap-4 mt-6 animate-in slide-in-from-bottom-4">
                                  <button onClick={() => handleAnswer('incorrect')} className="flex-1 py-4 bg-white border-2 border-rose-100 text-rose-500 rounded-2xl font-black uppercase flex items-center justify-center gap-2 shadow-md"><ThumbsDown size={18} /> Wrong</button>
                                  <button onClick={() => handleAnswer('correct')} className="flex-1 py-4 bg-emerald-600 text-white rounded-2xl font-black uppercase flex items-center justify-center gap-2 shadow-xl shadow-emerald-100"><ThumbsUp size={18} /> Correct</button>
                              </div>
                          )}
                       </div>
                     ) : (
                       <>
                          <div className="text-lg md:text-2xl font-black text-slate-900 leading-relaxed" dangerouslySetInnerHTML={{ __html: currentQ.data.questionText }} />
                          {currentQ.data.questionImage && (
                              <div className="w-full bg-slate-50 rounded-2xl border border-slate-100 p-4 flex justify-center">
                                  {!imgLoadError[currentQ.id + '_q'] ? (
                                    <img 
                                      src={currentQ.data.questionImage} 
                                      referrerPolicy="no-referrer"
                                      className="max-h-[40vh] object-contain rounded-xl" 
                                      alt="Diagram" 
                                      onError={() => handleImageError(currentQ.id + '_q')}
                                    />
                                  ) : (
                                    <div className="p-8 text-center flex flex-col items-center">
                                      <ImageOff size={40} className="text-slate-200 mb-2" />
                                      <a href={currentQ.data.questionImage} target="_blank" rel="noopener noreferrer" className="px-4 py-2 bg-slate-900 text-white rounded-lg text-xs font-black uppercase flex items-center gap-2">Show Original <ExternalLink size={14}/></a>
                                    </div>
                                  )}
                              </div>
                          )}
                          <div className="grid grid-cols-1 gap-2.5">
                              {currentQ.options.map((option, idx) => {
                                  const isSelected = currentQ.userAnswer === option;
                                  const isCorrect = option === currentQ.correctOption;
                                  const showResult = view === 'review' || (mode === 'practice' && !!currentQ.userAnswer);
                                  let btnClass = isSelected ? "border-red-600 bg-red-50 ring-2 ring-red-600" : "border-2 border-slate-100 hover:border-red-200 shadow-sm";
                                  if (showResult) btnClass = isCorrect ? "border-emerald-500 bg-emerald-50 ring-2 ring-emerald-500" : (isSelected ? "border-red-500 bg-red-50 ring-2 ring-red-500" : "opacity-40 grayscale scale-[0.98]");
                                  return (
                                  <button key={idx} onClick={() => handleAnswer(option)} disabled={showResult} className={`w-full p-4 rounded-xl text-left transition-all flex items-start gap-4 group ${btnClass}`}>
                                      <div className={`mt-0.5 w-6 h-6 rounded-md border flex items-center justify-center text-[10px] font-black ${showResult && isCorrect ? 'bg-emerald-500 text-white border-emerald-500' : 'text-slate-400'}`}>{String.fromCharCode(65 + idx)}</div>
                                      <div className="text-sm md:text-base font-bold text-slate-800" dangerouslySetInnerHTML={{ __html: option }} />
                                  </button>
                                  );
                              })}
                          </div>
                       </>
                     )}
                  </div>
               </div>
               <div className="p-4 border-t border-slate-100 bg-white flex justify-between items-center gap-3">
                  <button onClick={() => setCurrentQIndex(prev => prev - 1)} disabled={currentQIndex === 0} className="px-6 py-3 rounded-xl font-bold text-slate-500 hover:bg-slate-100 disabled:opacity-20 flex items-center gap-2 text-sm"><ChevronLeft size={16} /> Prev</button>
                  {currentQIndex === questions.length - 1 ? (
                    <button onClick={handleFinishSession} className="px-8 py-3 rounded-xl bg-slate-900 text-white font-black hover:bg-red-600 shadow-lg flex items-center gap-2 text-sm uppercase">Submit <CheckCircle2 size={16} /></button>
                  ) : (
                    <button onClick={() => setCurrentQIndex(prev => prev + 1)} className="px-8 py-3 rounded-xl bg-red-600 text-white font-black hover:bg-red-700 shadow-lg flex items-center gap-2 text-sm uppercase">Next <ChevronRight size={16} /></button>
                  )}
               </div>
            </div>
         </div>
      </div>

      {view === 'results' && (
        <div className="fixed inset-0 z-[100] bg-slate-50 overflow-y-auto p-4 md:p-8 animate-in fade-in duration-500">
           <div className="max-w-3xl mx-auto bg-white rounded-[3rem] shadow-2xl border border-slate-200 overflow-hidden">
              <div className="bg-slate-900 p-12 text-center text-white space-y-4">
                  <div className="inline-flex p-6 rounded-full bg-white/10 backdrop-blur-md mb-4 ring-1 ring-white/20">
                    <Trophy size={64} className="text-red-500" />
                  </div>
                  <h2 className="text-7xl font-black tracking-tighter">{(questions.filter(q => q.userAnswer === q.correctOption || q.userAnswer === 'correct').length / questions.length * 100).toFixed(0)}<span className="text-3xl opacity-50">%</span></h2>
                  <div className="text-xs font-bold uppercase tracking-[0.3em] text-slate-400">Score Evaluation</div>
              </div>
              <div className="p-8 grid grid-cols-3 divide-x border-b">
                 <div className="text-center space-y-1"><div className="text-3xl font-black text-emerald-500">{questions.filter(q => q.userAnswer === q.correctOption || q.userAnswer === 'correct').length}</div><div className="text-[9px] font-black text-slate-400 uppercase">Correct</div></div>
                 <div className="text-center space-y-1"><div className="text-3xl font-black text-rose-500">{questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption && q.userAnswer !== 'correct').length}</div><div className="text-[9px] font-black text-slate-400 uppercase">Wrong</div></div>
                 <div className="text-center space-y-1"><div className="text-3xl font-black text-slate-300">{questions.filter(q => !q.userAnswer).length}</div><div className="text-[9px] font-black text-slate-400 uppercase">Skipped</div></div>
              </div>
              <div className="p-10 space-y-4">
                  <button onClick={() => {setView('review'); setCurrentQIndex(0);}} className="w-full py-5 rounded-2xl bg-slate-900 text-white font-black text-lg uppercase tracking-widest hover:bg-red-600 transition-all flex items-center justify-center gap-3">Review Session</button>
                  <button onClick={() => setView('setup')} className="w-full py-4 rounded-2xl bg-white text-slate-400 font-bold uppercase text-xs flex items-center justify-center gap-2 border border-slate-100 hover:bg-slate-50">Main Menu</button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

